116→
117→    // 7. Logout
118→    await page.getByRole("button", { name: "Sign out" }).click();
119→
120→    // Should redirect to login, then we go to index
121→    await page.goto("/");
122→    await expect(
123→      page.getByRole("link", { name: "Create account" }).first()
124→    ).toBeVisible();
125→    await expect(
